"use client";

import {
  memo,
  useState,
  useCallback,
  type ReactNode,
} from "react";
import type { ContentPart, ToolCallEvent } from "@polpo-ai/sdk";
import { Copy, Check, FileCode } from "lucide-react";
import { Streamdown } from "streamdown";
import { getTextContent } from "../lib/get-text-content";
import { relativeTime } from "../lib/relative-time";
import { ToolCallChip } from "../tools";
import { ChatTyping } from "./chat-typing";

/** Components override accepted by Streamdown — use Record for flexibility. */
type StreamdownComponentsProp = Record<string, unknown>;

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export interface ChatMessageItemData {
  id?: string;
  role: "user" | "assistant";
  content: string | ContentPart[];
  ts?: string;
  toolCalls?: ToolCallEvent[];
}

export interface ChatMessageProps {
  msg: ChatMessageItemData;
  isLast?: boolean;
  isStreaming?: boolean;
  avatar?: ReactNode;
  agentName?: string;
  streamdownComponents?: StreamdownComponentsProp;
  /** Resolve a file_id to a URL for file attachment links. Defaults to `/api/v1/files/read?path=<file_id>`. */
  resolveFileUrl?: (fileId: string) => string;
  className?: string;
}

/* ------------------------------------------------------------------ */
/*  CopyButton                                                         */
/* ------------------------------------------------------------------ */

function CopyButton({ text }: { text: string }) {
  const [copied, setCopied] = useState(false);

  const handleCopy = useCallback(() => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 1500);
  }, [text]);

  return (
    <button
      type="button"
      onClick={handleCopy}
      aria-label="Copy message"
      className="inline-flex items-center justify-center rounded-md p-1 text-gray-400 hover:text-gray-900 hover:bg-gray-100 transition-colors"
    >
      {copied ? <Check className="size-3.5" /> : <Copy className="size-3.5" />}
    </button>
  );
}

/* ------------------------------------------------------------------ */
/*  File / image content parts                                         */
/* ------------------------------------------------------------------ */

const defaultResolveFileUrl = (fileId: string) =>
  `/api/v1/files/read?path=${encodeURIComponent(fileId)}`;

function ContentParts({
  parts,
  align,
  resolveFileUrl = defaultResolveFileUrl,
}: {
  parts: ContentPart[];
  align: "start" | "end";
  resolveFileUrl?: (fileId: string) => string;
}) {
  const nonText = parts.filter((p) => p.type !== "text");
  if (nonText.length === 0) return null;

  return (
    <div
      className={`flex flex-wrap gap-1.5 mb-1 ${align === "end" ? "justify-end" : ""}`}
    >
      {nonText.map((part, i) => {
        if (part.type === "image_url") {
          return (
            <a
              key={i}
              href={(part as { type: "image_url"; image_url: { url: string } }).image_url.url}
              target="_blank"
              rel="noopener noreferrer"
              className="rounded-lg overflow-hidden max-w-[200px]"
            >
              <img
                src={(part as { type: "image_url"; image_url: { url: string } }).image_url.url}
                alt=""
                className="w-full h-auto block"
              />
            </a>
          );
        }
        if (part.type === "file") {
          const fileId = (part as { type: "file"; file_id: string }).file_id;
          const fn = fileId.split("/").pop() || fileId;
          return (
            <a
              key={i}
              href={resolveFileUrl(fileId)}
              target="_blank"
              rel="noopener noreferrer"
              className="flex items-center gap-1.5 bg-gray-100 border border-gray-200 rounded-lg px-2.5 py-1.5 text-xs text-gray-900 hover:border-gray-400 transition-colors"
            >
              <FileCode size={13} />
              <span className="truncate max-w-[120px]">{fn}</span>
            </a>
          );
        }
        return null;
      })}
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  ChatUserMessage                                                    */
/* ------------------------------------------------------------------ */

export const ChatUserMessage = memo(
  function ChatUserMessage({
    msg,
    isLast,
    isStreaming,
    resolveFileUrl,
    className,
  }: {
    msg: ChatMessageItemData;
    isLast?: boolean;
    isStreaming?: boolean;
    resolveFileUrl?: (fileId: string) => string;
    className?: string;
  }) {
    const text = getTextContent(msg.content);

    return (
      <div className={`w-full px-6 py-3 ${className ?? ""}`}>
        <div className="max-w-3xl mx-auto">
          <div className="group flex w-full flex-col gap-2 ml-auto justify-end">
            {/* File/image parts */}
            {Array.isArray(msg.content) && (
              <ContentParts parts={msg.content} align="end" resolveFileUrl={resolveFileUrl} />
            )}

            {/* Message bubble */}
            <div className="w-fit max-w-[80%] ml-auto rounded-[18px_18px_4px_18px] bg-gray-100 px-4 py-3">
              {text ? (
                <p className="whitespace-pre-wrap break-words text-gray-900">
                  {text}
                </p>
              ) : null}
            </div>

            {/* Hover actions: timestamp + copy */}
            {text && (!isLast || !isStreaming) && (
              <div className="flex items-center justify-end gap-1.5 h-6">
                <span className="text-[11px] text-gray-400 opacity-0 group-hover:opacity-100 transition-opacity">
                  {msg.ts ? relativeTime(msg.ts) : ""}
                </span>
                <div className="opacity-0 group-hover:opacity-100 transition-opacity">
                  <CopyButton text={text} />
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  },
  (prev, next) =>
    prev.isLast === next.isLast &&
    prev.isStreaming === next.isStreaming &&
    prev.msg.id === next.msg.id &&
    prev.msg.content === next.msg.content,
);

/* ------------------------------------------------------------------ */
/*  ChatAssistantMessage                                               */
/* ------------------------------------------------------------------ */

export const ChatAssistantMessage = memo(
  function ChatAssistantMessage({
    msg,
    isLast,
    isStreaming,
    avatar,
    agentName,
    streamdownComponents: components,
    resolveFileUrl,
    className,
  }: {
    msg: ChatMessageItemData;
    isLast?: boolean;
    isStreaming?: boolean;
    avatar?: ReactNode;
    agentName?: string;
    streamdownComponents?: StreamdownComponentsProp;
    resolveFileUrl?: (fileId: string) => string;
    className?: string;
  }) {
    const text = getTextContent(msg.content);
    const filteredToolCalls = msg.toolCalls?.filter(
      (tc) => tc.name !== "ask_user_question",
    );

    return (
      <div className={`w-full px-6 pt-4 pb-6 ${className ?? ""}`}>
        <div className="max-w-3xl mx-auto">
          <div className="group flex w-full flex-col gap-2">
            {/* Avatar + name header */}
            {(avatar || agentName) && (
              <div className="flex items-center gap-2 mb-1">
                {avatar}
                {agentName && (
                  <span className="text-[13px] font-semibold text-gray-900">
                    {agentName}
                  </span>
                )}
              </div>
            )}

            {/* Tool calls */}
            {filteredToolCalls && filteredToolCalls.length > 0 && (
              <div className="flex flex-col gap-1 mb-1">
                {filteredToolCalls.map((tc) => (
                  <ToolCallChip key={tc.id} tool={tc} />
                ))}
              </div>
            )}

            {/* File/image parts */}
            {Array.isArray(msg.content) && (
              <ContentParts parts={msg.content} align="start" resolveFileUrl={resolveFileUrl} />
            )}

            {/* Text content or typing dots */}
            <div className="w-full text-gray-900">
              {text ? (
                components ? (
                  <Streamdown
                    className="size-full [&>*:first-child]:mt-0 [&>*:last-child]:mb-0"
                    components={components as any}
                  >
                    {text}
                  </Streamdown>
                ) : (
                  <p className="whitespace-pre-wrap break-words">{text}</p>
                )
              ) : (
                !filteredToolCalls?.length && <ChatTyping className="pt-1" />
              )}
            </div>

            {/* Hover action: copy */}
            {text && (!isLast || !isStreaming) && (
              <div className="h-6 flex items-center opacity-0 group-hover:opacity-100 transition-opacity">
                <CopyButton text={text} />
              </div>
            )}
          </div>
        </div>
      </div>
    );
  },
  (prev, next) =>
    prev.avatar === next.avatar &&
    prev.agentName === next.agentName &&
    prev.isLast === next.isLast &&
    prev.isStreaming === next.isStreaming &&
    prev.streamdownComponents === next.streamdownComponents &&
    prev.msg.id === next.msg.id &&
    prev.msg.content === next.msg.content &&
    prev.msg.toolCalls?.length === next.msg.toolCalls?.length &&
    JSON.stringify(prev.msg.toolCalls?.map((t) => t.state)) ===
      JSON.stringify(next.msg.toolCalls?.map((t) => t.state)),
);

/* ------------------------------------------------------------------ */
/*  ChatMessage — dispatcher                                           */
/* ------------------------------------------------------------------ */

export const ChatMessage = memo(
  function ChatMessage({
    msg,
    isLast,
    isStreaming,
    avatar,
    agentName,
    streamdownComponents,
    resolveFileUrl,
    className,
  }: ChatMessageProps) {
    if (msg.role === "user") {
      return (
        <ChatUserMessage msg={msg} isLast={isLast} isStreaming={isStreaming} resolveFileUrl={resolveFileUrl} className={className} />
      );
    }

    return (
      <ChatAssistantMessage
        msg={msg}
        isLast={isLast}
        isStreaming={isStreaming}
        avatar={avatar}
        agentName={agentName}
        streamdownComponents={streamdownComponents}
        resolveFileUrl={resolveFileUrl}
        className={className}
      />
    );
  },
  (prev, next) =>
    prev.avatar === next.avatar &&
    prev.agentName === next.agentName &&
    prev.isLast === next.isLast &&
    prev.isStreaming === next.isStreaming &&
    prev.streamdownComponents === next.streamdownComponents &&
    prev.resolveFileUrl === next.resolveFileUrl &&
    prev.className === next.className &&
    prev.msg.id === next.msg.id &&
    prev.msg.content === next.msg.content &&
    prev.msg.role === next.msg.role &&
    prev.msg.toolCalls?.length === next.msg.toolCalls?.length &&
    JSON.stringify(prev.msg.toolCalls?.map((t) => t.state)) ===
      JSON.stringify(next.msg.toolCalls?.map((t) => t.state)),
);

"use client";

import {
  useCallback,
  useEffect,
  useImperativeHandle,
  useRef,
  useState,
  type ReactNode,
} from "react";
import { Virtuoso, type VirtuosoHandle } from "react-virtuoso";
import type { ChatMessage } from "@polpo-ai/sdk";
import { useChatContext } from "./chat-provider";
import { ChatSkeleton } from "./chat-skeleton";
import { ChatScrollButton } from "./chat-scroll-button";
import { getTextContent } from "../lib/get-text-content";

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export interface ChatMessagesHandle {
  /** Scroll the list to the bottom. */
  scrollToBottom: (behavior?: "smooth" | "auto") => void;
}

export interface ChatMessagesProps {
  /**
   * Custom renderer for each message.
   * Receives the message, its index, whether it is the last item, and
   * whether the assistant is currently streaming.
   */
  renderItem?: (
    msg: ChatMessage,
    index: number,
    isLast: boolean,
    isStreaming: boolean,
  ) => ReactNode;
  /** Extra classes applied to the Virtuoso container. */
  className?: string;
  /** Number of skeleton pairs to show during the initial load. */
  skeletonCount?: number;
}

/* ------------------------------------------------------------------ */
/*  Default renderer (plain text fallback)                             */
/* ------------------------------------------------------------------ */

function DefaultMessageItem({ msg }: { msg: ChatMessage }) {
  const text = getTextContent(msg.content);
  return (
    <div className="w-full px-6 py-3">
      <div className="max-w-3xl mx-auto">
        <p className="text-xs font-medium opacity-50 mb-1">
          {msg.role === "user" ? "You" : "Assistant"}
        </p>
        <p className="whitespace-pre-wrap">{text}</p>
      </div>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Footer (keeps Virtuoso happy for follow-output)                    */
/* ------------------------------------------------------------------ */

function VirtuosoFooter() {
  return <div className="h-px" aria-hidden="true" />;
}

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

export function ChatMessages({
  renderItem,
  className,
  skeletonCount = 3,
  ref,
}: ChatMessagesProps & { ref?: React.Ref<ChatMessagesHandle> }) {
    const { messages, isStreaming, status } = useChatContext();

    /* ── Virtuoso ref & scroll state ────────────────────────────── */
    const virtuosoRef = useRef<VirtuosoHandle>(null);
    const [isAtBottom, setIsAtBottom] = useState(true);
    const [showNewMessage, setShowNewMessage] = useState(false);
    const prevMessageCountRef = useRef(0);
    const hasInitialScrollRef = useRef(false);

    /* ── Scroll helpers ─────────────────────────────────────────── */
    const scrollToBottom = useCallback(
      (behavior: "smooth" | "auto" = "smooth") => {
        virtuosoRef.current?.scrollToIndex({
          index: "LAST",
          align: "end",
          behavior,
        });
        setShowNewMessage(false);
      },
      [],
    );

    useImperativeHandle(ref, () => ({ scrollToBottom }), [scrollToBottom]);

    /* ── Bottom-state change handler ────────────────────────────── */
    const handleAtBottomStateChange = useCallback((atBottom: boolean) => {
      setIsAtBottom(atBottom);
      if (atBottom) setShowNewMessage(false);
    }, []);

    /* ── Initial scroll to bottom once messages load ────────────── */
    useEffect(() => {
      if (messages.length > 0 && !hasInitialScrollRef.current) {
        hasInitialScrollRef.current = true;
        requestAnimationFrame(() =>
          virtuosoRef.current?.scrollToIndex({
            index: "LAST",
            align: "end",
            behavior: "auto",
          }),
        );
      }
    }, [messages.length]);

    /* ── Reset scroll flag when data source changes ─────────────── */
    useEffect(() => {
      hasInitialScrollRef.current = false;
    }, [status]);

    /* ── Show "new messages" badge when not at bottom ───────────── */
    useEffect(() => {
      const cur = messages.length;
      const prev = prevMessageCountRef.current;
      if (cur > prev && !isAtBottom && prev > 0) {
        setShowNewMessage(true);
      }
      prevMessageCountRef.current = cur;
    }, [messages.length, isAtBottom]);

    /* ── Item renderer ──────────────────────────────────────────── */
    const itemContent = useCallback(
      (index: number, msg: ChatMessage) => {
        const isLast = index === messages.length - 1;
        if (renderItem) {
          return renderItem(msg, index, isLast, isStreaming);
        }
        return <DefaultMessageItem msg={msg} />;
      },
      [messages.length, isStreaming, renderItem],
    );

    /* ── Loading state ──────────────────────────────────────────── */
    if (status === "loading") {
      return (
        <div className={`flex-1 overflow-hidden ${className ?? ""}`}>
          <ChatSkeleton count={skeletonCount} />
        </div>
      );
    }

    /* ── Main list ──────────────────────────────────────────────── */
    return (
      <div className={`relative flex-1 min-h-0 ${className ?? ""}`}>
        <Virtuoso
          ref={virtuosoRef}
          data={messages}
          followOutput="auto"
          atBottomStateChange={handleAtBottomStateChange}
          atBottomThreshold={100}
          defaultItemHeight={120}
          overscan={500}
          increaseViewportBy={{ top: 300, bottom: 300 }}
          skipAnimationFrameInResizeObserver
          itemContent={itemContent}
          className="h-full"
          components={{ Footer: VirtuosoFooter }}
        />

        <ChatScrollButton
          isAtBottom={isAtBottom}
          showNewMessage={showNewMessage}
          onClick={() => scrollToBottom()}
        />
      </div>
    );
}

"use client";

import {
  createContext,
  useContext,
  type ReactNode,
} from "react";
import { useChat, type UseChatReturn } from "@polpo-ai/react";
import { useFiles } from "@polpo-ai/react";

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export interface ChatProviderProps {
  /** Resume an existing session by ID. */
  sessionId?: string;
  /** Target a specific agent for direct conversation. */
  agent?: string;
  /** Called when a new session is created (first message). */
  onSessionCreated?: (id: string) => void;
  /** Called after each stream update (e.g. scroll-to-bottom). */
  onUpdate?: () => void;
  children: ReactNode;
}

export interface ChatContextValue extends UseChatReturn {
  /** Upload a file attachment (delegates to useFiles). */
  uploadFile: (
    destPath: string,
    file: File | Blob,
    filename: string,
  ) => Promise<{ uploaded: { name: string; size: number }[]; count: number }>;
  /** Whether a file upload is in progress. */
  isUploading: boolean;
}

/* ------------------------------------------------------------------ */
/*  Context                                                            */
/* ------------------------------------------------------------------ */

const ChatContext = createContext<ChatContextValue | null>(null);

/* ------------------------------------------------------------------ */
/*  Provider                                                           */
/* ------------------------------------------------------------------ */

export function ChatProvider({
  sessionId,
  agent,
  onSessionCreated,
  onUpdate,
  children,
}: ChatProviderProps) {
  const chat = useChat({
    sessionId,
    agent,
    onSessionCreated,
    onUpdate,
  });

  const { uploadFile, isUploading } = useFiles();

  const value: ChatContextValue = {
    ...chat,
    uploadFile,
    isUploading,
  };

  return <ChatContext.Provider value={value}>{children}</ChatContext.Provider>;
}

/* ------------------------------------------------------------------ */
/*  Consumer hook                                                      */
/* ------------------------------------------------------------------ */

export function useChatContext(): ChatContextValue {
  const ctx = useContext(ChatContext);
  if (!ctx) {
    throw new Error("useChatContext must be used within a <ChatProvider>");
  }
  return ctx;
}

"use client";

import { ArrowDown } from "lucide-react";

/* ------------------------------------------------------------------ */
/*  Scroll-to-bottom button with optional new-message indicator        */
/* ------------------------------------------------------------------ */

interface ChatScrollButtonProps {
  isAtBottom: boolean;
  showNewMessage?: boolean;
  onClick: () => void;
  className?: string;
}

export function ChatScrollButton({
  isAtBottom,
  showNewMessage,
  onClick,
  className,
}: ChatScrollButtonProps) {
  if (isAtBottom) return null;

  return (
    <button
      type="button"
      aria-label="Scroll to bottom"
      onClick={onClick}
      className={`absolute bottom-4 left-1/2 -translate-x-1/2 z-10 flex h-8 w-8 items-center justify-center rounded-full border border-gray-200 bg-gray-50 shadow-md transition-colors hover:bg-gray-100 ${className ?? ""}`}
    >
      <ArrowDown className="h-4 w-4 text-gray-600" />

      {showNewMessage && (
        <span className="absolute -top-1 -right-1 flex h-3 w-3">
          <span className="absolute inline-flex h-full w-full animate-ping rounded-full bg-blue-500 opacity-75" />
          <span className="relative inline-flex h-3 w-3 rounded-full bg-blue-500" />
        </span>
      )}
    </button>
  );
}

"use client";

import { memo, useMemo, useCallback } from "react";
import { Trash2, MessageSquare } from "lucide-react";
import type { ChatSession, AgentConfig } from "@polpo-ai/sdk";
import { relativeTime } from "../lib/relative-time";

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export interface ChatSessionListProps {
  /** Session list (from useSessions().sessions) */
  sessions: ChatSession[];
  /** Agents list (from useAgents().agents) — used to show agent names */
  agents?: AgentConfig[];
  /** Currently active session ID (highlighted) */
  activeSessionId?: string | null;
  /** Called when a session is selected */
  onSelect: (sessionId: string) => void;
  /** Called when delete is requested. Omit to hide delete buttons. */
  onDelete?: (sessionId: string) => void;
  /** Whether the list is loading */
  isLoading?: boolean;
  /** Empty state message */
  emptyMessage?: string;
  /** Additional className on the outer container */
  className?: string;
  /** Custom avatar renderer for an agent */
  renderAvatar?: (agent: AgentConfig | undefined, agentName: string) => React.ReactNode;
}

/* ------------------------------------------------------------------ */
/*  Session item                                                       */
/* ------------------------------------------------------------------ */

const SessionItem = memo(function SessionItem({
  session,
  agentMap,
  isActive,
  onSelect,
  onDelete,
  renderAvatar,
}: {
  session: ChatSession;
  agentMap: Map<string, AgentConfig>;
  isActive: boolean;
  onSelect: (id: string) => void;
  onDelete?: (id: string) => void;
  renderAvatar?: (agent: AgentConfig | undefined, name: string) => React.ReactNode;
}) {
  const agentName = session.agent || "assistant";
  const agent = agentMap.get(agentName);
  const displayName = agent?.identity?.displayName || agent?.name || agentName;

  const handleDelete = useCallback(
    (e: React.MouseEvent) => {
      e.stopPropagation();
      onDelete?.(session.id);
    },
    [onDelete, session.id],
  );

  return (
    <div
      role="button"
      tabIndex={0}
      onClick={() => onSelect(session.id)}
      onKeyDown={(e) => { if (e.key === "Enter" || e.key === " ") { e.preventDefault(); onSelect(session.id); } }}
      className={`flex items-center gap-3 w-full px-3 py-2.5 rounded-xl text-left transition-all duration-150 cursor-pointer group ${
        isActive
          ? "bg-gray-100"
          : "hover:bg-gray-50"
      }`}
    >
      {/* Avatar */}
      {renderAvatar ? (
        renderAvatar(agent, agentName)
      ) : (
        <div className="flex items-center justify-center size-8 rounded-lg bg-gray-200 text-gray-600 text-xs font-semibold shrink-0">
          {displayName.charAt(0).toUpperCase()}
        </div>
      )}

      {/* Content */}
      <div className="flex-1 min-w-0">
        <div className="text-sm font-medium text-gray-900 truncate">
          {session.title || session.id.slice(0, 24)}
        </div>
        <div className="flex items-center gap-1.5 mt-0.5">
          <span className="text-xs text-gray-500 truncate">{displayName}</span>
          {session.updatedAt && (
            <>
              <span className="text-gray-300">·</span>
              <span className="text-[11px] text-gray-400 shrink-0">
                {relativeTime(session.updatedAt)}
              </span>
            </>
          )}
        </div>
      </div>

      {/* Delete */}
      {onDelete && (
        <button
          type="button"
          onClick={handleDelete}
          className="opacity-0 group-hover:opacity-100 p-1.5 rounded-md text-gray-400 hover:text-red-500 hover:bg-red-50 transition-all"
          aria-label="Delete session"
        >
          <Trash2 className="size-3.5" />
        </button>
      )}
    </div>
  );
});

/* ------------------------------------------------------------------ */
/*  Main component                                                     */
/* ------------------------------------------------------------------ */

export function ChatSessionList({
  sessions,
  agents,
  activeSessionId,
  onSelect,
  onDelete,
  isLoading,
  emptyMessage = "No conversations yet",
  className,
  renderAvatar,
}: ChatSessionListProps) {
  const agentMap = useMemo(() => {
    const map = new Map<string, AgentConfig>();
    if (agents) for (const a of agents) map.set(a.name, a);
    return map;
  }, [agents]);

  if (isLoading) {
    return (
      <div className={`flex flex-col gap-1 ${className || ""}`}>
        {Array.from({ length: 5 }).map((_, i) => (
          <div key={i} className="flex items-center gap-3 px-3 py-2.5">
            <div className="size-8 rounded-lg bg-gray-100 animate-pulse" />
            <div className="flex-1 space-y-1.5">
              <div className="h-3.5 w-3/4 rounded bg-gray-100 animate-pulse" />
              <div className="h-3 w-1/2 rounded bg-gray-100 animate-pulse" />
            </div>
          </div>
        ))}
      </div>
    );
  }

  if (sessions.length === 0) {
    return (
      <div className={`flex flex-col items-center justify-center py-12 ${className || ""}`}>
        <MessageSquare className="size-8 text-gray-300 mb-3" />
        <p className="text-sm text-gray-400">{emptyMessage}</p>
      </div>
    );
  }

  return (
    <div className={`flex flex-col gap-0.5 ${className || ""}`}>
      {sessions.map((s) => (
        <SessionItem
          key={s.id}
          session={s}
          agentMap={agentMap}
          isActive={s.id === activeSessionId}
          onSelect={onSelect}
          onDelete={onDelete}
          renderAvatar={renderAvatar}
        />
      ))}
    </div>
  );
}

