"use client";

import { useCallback, type ReactNode } from "react";
import { ChatProvider } from "./chat-provider";
import { useChatContext } from "./chat-provider";
import { ChatMessages, type ChatMessagesHandle } from "./chat-messages";
import { ChatMessage, type ChatMessageProps } from "./chat-message";
import { ChatInput } from "./chat-input";
import { streamdownComponents as defaultStreamdownComponents } from "./streamdown-code";

// ── Props ──

export interface ChatRenderContext {
  hasMessages: boolean;
}

export interface ChatProps {
  /** Session ID — omit for new chats */
  sessionId?: string;
  /** Agent name for completions */
  agent?: string;
  /** Called when a new session is created */
  onSessionCreated?: (sessionId: string) => void;
  /** Called on each stream update (useful for external scroll control) */
  onUpdate?: () => void;
  /** Custom message renderer — if omitted, uses ChatMessage with defaults */
  renderMessage?: (msg: ChatMessageProps["msg"], index: number, isLast: boolean, isStreaming: boolean) => ReactNode;
  /** Avatar ReactNode shown on assistant messages */
  avatar?: ReactNode;
  /** Agent display name shown on assistant messages */
  agentName?: string;
  /** Streamdown components override for code blocks etc. */
  streamdownComponents?: Record<string, unknown>;
  /** Number of skeleton items while loading */
  skeletonCount?: number;
  /** Placeholder text for the default input */
  inputPlaceholder?: string;
  /** Hint text below the default input */
  inputHint?: string;
  /** Whether file attachments are enabled on the default input (default: true) */
  allowAttachments?: boolean;
  /** Children rendered after the message list — replaces the default ChatInput.
   *  Can be a render function receiving `{ hasMessages }` for conditional rendering. */
  children?: ReactNode | ((ctx: ChatRenderContext) => ReactNode);
  /** Additional className on the outer container */
  className?: string;
}

// ── Inner component (needs context) ──

function ChatInner({
  ref,
  renderMessage,
  avatar,
  agentName,
  streamdownComponents,
  skeletonCount,
  inputPlaceholder,
  inputHint,
  allowAttachments,
  children,
  className,
}: Omit<ChatProps, "sessionId" | "agent" | "onSessionCreated" | "onUpdate"> & {
  ref?: React.Ref<ChatMessagesHandle>;
}) {
  const { messages } = useChatContext();
  const hasMessages = messages.length > 0;
  const hasChildren = children !== undefined && children !== null;
  const isRenderFunction = typeof children === "function";

  const defaultRender = useCallback(
    (msg: ChatMessageProps["msg"], _index: number, isLast: boolean, isStreaming: boolean) => (
      <ChatMessage
        msg={msg}
        isLast={isLast}
        isStreaming={isStreaming}
        avatar={avatar}
        agentName={agentName}
        streamdownComponents={(streamdownComponents ?? defaultStreamdownComponents) as Record<string, unknown>}
      />
    ),
    [avatar, agentName, streamdownComponents],
  );

  // Resolve children content
  let content: ReactNode;
  if (isRenderFunction) {
    content = children({ hasMessages });
  } else if (hasChildren) {
    content = children;
  } else {
    content = (
      <ChatInput
        placeholder={inputPlaceholder}
        hint={inputHint}
        allowAttachments={allowAttachments}
      />
    );
  }

  // When using render function and no messages yet, skip the message list
  // (landing page pattern)
  if (isRenderFunction && !hasMessages) {
    return (
      <div className={`flex flex-col min-w-0 min-h-0 ${className || ""}`}>
        {content}
      </div>
    );
  }

  return (
    <div className={`flex flex-col min-w-0 min-h-0 ${className || ""}`}>
      <ChatMessages
        ref={ref}
        renderItem={renderMessage || defaultRender}
        skeletonCount={skeletonCount}
        className="flex-1"
      />
      {content}
    </div>
  );
}

// ── Public component ──

export function Chat({
  sessionId,
  agent,
  onSessionCreated,
  onUpdate,
  ref,
  ...rest
}: ChatProps & { ref?: React.Ref<ChatMessagesHandle> }) {
  return (
    <ChatProvider
      sessionId={sessionId}
      agent={agent}
      onSessionCreated={onSessionCreated}
      onUpdate={onUpdate}
    >
      <ChatInner ref={ref} {...rest} />
    </ChatProvider>
  );
}

"use client";

import type { ComponentType, HTMLAttributes } from "react";

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

/** Props that any code-block component must accept. */
export interface CodeBlockComponentProps {
  code: string;
  language: string;
  children?: React.ReactNode;
}

/** The shape returned by createStreamdownComponents / the default export. */
export interface StreamdownComponents {
  code: (
    props: HTMLAttributes<HTMLElement> & {
      node?: unknown;
      "data-block"?: string;
    },
  ) => React.ReactNode;
}

/* ------------------------------------------------------------------ */
/*  Fallback code block (simple <pre><code>)                           */
/* ------------------------------------------------------------------ */

function FallbackCodeBlock({ code, language }: CodeBlockComponentProps) {
  return (
    <pre
      data-language={language}
      style={{
        margin: "0.75rem 0",
        padding: "0.875rem 1rem",
        borderRadius: "10px",
        overflowX: "auto",
        border: "1px solid #e5e7eb",
        background: "#f9fafb",
        color: "inherit",
        fontSize: "0.75rem",
        lineHeight: "1.625",
      }}
    >
      <code className={`language-${language}`}>{code}</code>
    </pre>
  );
}

/* ------------------------------------------------------------------ */
/*  Factory                                                            */
/* ------------------------------------------------------------------ */

/**
 * Create a `streamdownComponents` override object for Streamdown.
 *
 * Pass your own `CodeBlock` component to get syntax-highlighted fenced
 * code blocks. If omitted, a plain `<pre><code>` fallback is used.
 *
 * @example
 * ```tsx
 * import { CodeBlock } from "@/components/ai-elements/code-block";
 * import { createStreamdownComponents } from "@polpo-ai/chat";
 *
 * const streamdownComponents = createStreamdownComponents(CodeBlock);
 * ```
 */
export function createStreamdownComponents(
  CodeBlockComponent?: ComponentType<CodeBlockComponentProps>,
): StreamdownComponents {
  const Block = CodeBlockComponent ?? FallbackCodeBlock;

  function StreamdownCode(
    props: HTMLAttributes<HTMLElement> & {
      node?: unknown;
      "data-block"?: string;
    },
  ) {
    const {
      children,
      className,
      node: _,
      "data-block": dataBlock,
      ...rest
    } = props;

    // Fenced code blocks carry data-block; inline code does not.
    if (dataBlock !== undefined) {
      const match = /language-(\w+)/.exec(className || "");
      const lang = match?.[1] || "text";
      const code = String(children).replace(/\n$/, "");
      return <Block code={code} language={lang} />;
    }

    return (
      <code className={className} {...rest}>
        {children}
      </code>
    );
  }

  return { code: StreamdownCode };
}

/* ------------------------------------------------------------------ */
/*  Pre-built instance — uses the plain fallback                       */
/* ------------------------------------------------------------------ */

export const streamdownComponents: StreamdownComponents =
  createStreamdownComponents();

"use client";

import type { ToolCallEvent } from "@polpo-ai/sdk";
import { Wrench } from "lucide-react";
import { ToolCallShell } from "./tool-call-shell";
import { ToolRead } from "./tool-read";
import { ToolWrite } from "./tool-write";
import { ToolBash } from "./tool-bash";
import { ToolSearch } from "./tool-search";
import { ToolHttp } from "./tool-http";
import { ToolEmail } from "./tool-email";
import { ToolAskUser } from "./tool-ask-user";

// ── Tool name → component map ──

const TOOL_COMPONENTS: Record<string, React.ComponentType<{ tool: ToolCallEvent }>> = {
  ask_user_question: ToolAskUser,
  read: ToolRead,
  read_attachment: ToolRead,
  write: ToolWrite,
  edit: ToolWrite,
  bash: ToolBash,
  grep: ToolSearch,
  glob: ToolSearch,
  search_web: ToolHttp,
  http_fetch: ToolHttp,
  http_download: ToolHttp,
  email_send: ToolEmail,
};

// Prefix-based matching for tools like browser_*, memory_*, etc.
const TOOL_PREFIX_COMPONENTS: { prefix: string; component: React.ComponentType<{ tool: ToolCallEvent }> }[] = [
  { prefix: "browser_", component: ToolHttp },
  { prefix: "email_", component: ToolEmail },
  { prefix: "search_", component: ToolSearch },
];

function getToolLabel(name: string) {
  return name.replace(/_/g, " ").replace(/\b\w/g, (c) => c.toUpperCase());
}

// ── Dispatcher ──

export function ToolCallChip({ tool }: { tool: ToolCallEvent }) {
  // Exact match
  const Exact = TOOL_COMPONENTS[tool.name];
  if (Exact) return <Exact tool={tool} />;

  // Prefix match
  for (const { prefix, component: Prefixed } of TOOL_PREFIX_COMPONENTS) {
    if (tool.name.startsWith(prefix)) return <Prefixed tool={tool} />;
  }

  // Generic fallback
  const summary = tool.arguments
    ? Object.values(tool.arguments).find((v) => typeof v === "string" && v.length > 0) as string | undefined
    : undefined;

  return (
    <ToolCallShell
      tool={tool}
      icon={Wrench}
      label={getToolLabel(tool.name)}
      summary={summary?.slice(0, 80)}
    />
  );
}

