import { useState, useRef, useEffect } from "react";

/** Track document-level drag state for visual feedback */
export function useDocumentDrag() {
  const [dragging, setDragging] = useState(false);
  const counterRef = useRef(0);
  useEffect(() => {
    const onEnter = (e: DragEvent) => { if (e.dataTransfer?.types?.includes("Files")) { counterRef.current++; setDragging(true); } };
    const onLeave = () => { counterRef.current--; if (counterRef.current === 0) setDragging(false); };
    const onDrop = () => { counterRef.current = 0; setDragging(false); };
    document.addEventListener("dragenter", onEnter);
    document.addEventListener("dragleave", onLeave);
    document.addEventListener("drop", onDrop);
    return () => { document.removeEventListener("dragenter", onEnter); document.removeEventListener("dragleave", onLeave); document.removeEventListener("drop", onDrop); };
  }, []);
  return dragging;
}

"use client";

import { useCallback } from "react";
import type { ContentPart } from "@polpo-ai/sdk";

/** Shape of the message emitted by the PromptInput component. */
export interface PromptInputMessage {
  text: string;
  files: { url: string; filename?: string }[];
}

/** Shared submit handler — uploads files via SDK then sends ContentPart[] */
export function useSubmitHandler(
  sendMessage: (content: string | ContentPart[]) => Promise<void>,
  uploadFile: (destPath: string, file: Blob, filename: string) => Promise<unknown>,
) {
  return useCallback(async (message: PromptInputMessage) => {
    const text = message.text.trim();
    const files = message.files || [];
    if (!text && files.length === 0) return;

    if (files.length > 0) {
      const parts: ContentPart[] = [];
      if (text) parts.push({ type: "text", text });
      for (const f of files) {
        const name = f.filename || "upload";
        try {
          const res = await fetch(f.url);
          const blob = await res.blob();
          await uploadFile("workspace", blob, name);
          parts.push({ type: "file", file_id: `workspace/${name}` });
        } catch { /* skip failed uploads */ }
      }
      if (parts.length > 0) sendMessage(parts);
    } else {
      sendMessage(text);
    }
  }, [sendMessage, uploadFile]);
}

import type { ContentPart } from "@polpo-ai/sdk";

/** Extract the concatenated text from a message content value (string or ContentPart[]). */
export function getTextContent(content: string | ContentPart[]): string {
  if (typeof content === "string") return content;
  return content
    .filter((p): p is { type: "text"; text: string } => p.type === "text")
    .map((p) => p.text)
    .join("");
}

/** Format an ISO timestamp as a human-readable relative time string. */
export function relativeTime(iso: string): string {
  const now = Date.now();
  const then = new Date(iso).getTime();
  const diff = Math.floor((now - then) / 1000);
  if (diff < 10) return "Just now";
  if (diff < 60) return `${diff}s ago`;
  const mins = Math.floor(diff / 60);
  if (mins < 60) return mins === 1 ? "A minute ago" : `${mins}m ago`;
  const hours = Math.floor(mins / 60);
  if (hours < 24) return hours === 1 ? "An hour ago" : `${hours}h ago`;
  return new Date(iso).toLocaleString(undefined, { month: "short", day: "numeric", hour: "2-digit", minute: "2-digit" });
}
